// sample cpp build scrfipt without sql or cics or zunit// wip header rules busted@groovy.transform.BaseScript com.ibm.dbb.groovy.ScriptLoader baseScriptimport com.ibm.dbb.repository.*import com.ibm.dbb.dependency.*import com.ibm.dbb.build.*import groovy.transform.*import com.ibm.dbb.build.report.*import com.ibm.dbb.build.report.records.*// define script properties@Field BuildProperties props = BuildProperties.getInstance()@Field def buildUtils= loadScript(new File("${props.zAppBuildDir}/utilities/BuildUtilities.groovy"))@Field def impactUtils= loadScript(new File("${props.zAppBuildDir}/utilities/ImpactUtilities.groovy"))@Field RepositoryClient repositoryClientprintln("** Building files mapped to ${this.class.getName()}.groovy script")// verify required build propertiesbuildUtils.assertBuildProperties(props.cpp_requiredBuildProperties)def langQualifier = "cpp"buildUtils.createLanguageDatasets(langQualifier)// sort the build list based on build file rank if providedList<String> sortedList = buildUtils.sortBuildList(argMap.buildList, 'cpp_fileBuildRank')// iterate through build listsortedList.each { buildFile ->	println "*** Building file $buildFile"	String rules = props.getFileProperty('cpp_resolutionRules', buildFile)	String cpp_srcPDS = props.getFileProperty('cpp_srcPDS', buildFile)	DependencyResolver dependencyResolver = buildUtils.createDependencyResolver(buildFile, rules)	buildUtils.copySourceFiles(buildFile, cpp_srcPDS, props.cpp_macroPDS, dependencyResolver)	// create mvs commands	LogicalFile logicalFile = dependencyResolver.getLogicalFile()	String member = CopyToPDS.createMemberName(buildFile)	File logFile = new File( props.userBuild ? "${props.buildOutDir}/${member}.log" : "${props.buildOutDir}/${member}.asm.log")	if (logFile.exists())	logFile.delete()	MVSExec cpp = createcppCommand(buildFile, logicalFile, member, logFile)	MVSExec linkEdit = createLinkEditCommand(buildFile, logicalFile, member, logFile)	// execute mvs commands in a mvs job	MVSJob job = new MVSJob()	job.start()	// initialize return codes	int rc = 0	int maxRC = props.getFileProperty('cpp_maxRC', buildFile).toInteger()	// SQL preprocessor	if (buildUtils.isSQL(logicalFile)){        println "**! ERROR: CPP SQL NOT SUPPORTED"        props.error = "true"	}	// CICS preprocessor	if (buildUtils.isCICS(logicalFile)){        println "**! ERROR: CPP CICS NOT SUPPORTED"        props.error = "true"			}	// cpp    rc = cpp.execute()	maxRC = props.getFileProperty('cpp_maxRC', buildFile).toInteger()	if (rc > maxRC) {		String errorMsg = "*! The cpp return code ($rc) for $buildFile exceeded the maximum return code allowed ($maxRC)"    	println(errorMsg)		props.error = "true"		buildUtils.updateBuildResult(errorMsg:errorMsg,logs:Ý"${member}.log":logFile¨,client:getRepositoryClient())		}	else {		// if this program needs to be link edited . . .		String needsLinking = props.getFileProperty('cpp_linkEdit', buildFile)		if (needsLinking && needsLinking.toBoolean()) {			rc = linkEdit.execute()			maxRC = props.getFileProperty('cpp_linkEditMaxRC', buildFile).toInteger()			if (rc > maxRC) {				String errorMsg = "*! The link edit return code ($rc) for $buildFile exceeded the maximum return code allowed ($maxRC)"				println(errorMsg)				props.error = "true"				buildUtils.updateBuildResult(errorMsg:errorMsg,logs:Ý"${member}.log":logFile¨,client:getRepositoryClient())			}			else {				// only scan the load module if load module scanning turned on for file				if(!props.userBuild){					String scanLoadModule = props.getFileProperty('cpp_scanLoadModule', buildFile)					if (scanLoadModule && scanLoadModule.toBoolean() && getRepositoryClient()) {						String cpp_loadPDS = props.getFileProperty('cpp_loadPDS', buildFile)						impactUtils.saveStaticLinkDependencies(buildFile, cpp_loadPDS, logicalFile, repositoryClient)					}				}			}		}	}	// clean up passed DD statements	job.stop()}// end script/* * createCompileCommand - creates a MVSExec command for compiling the BMS Map (buildFile) */def createcppCommand(String buildFile, LogicalFile logicalFile, String member, File logFile) {	def errPrefixOptions = props.getFileProperty('cpp_compileErrorPrefixParms', buildFile) ?: ""    String parameters = props.getFileProperty('cpp_pgmParms', buildFile)	if (props.errPrefix) parameters = "$parameters,$errPrefixOptions"	MVSExec cpp = new MVSExec().file(buildFile).pgm(props.cpp_pgm).parm(parameters)    cpp.dd(new DDStatement().name("TASKLIB").dsn("CEE.SCEERUN2").options("shr"))                    cpp.dd(new DDStatement().dsn("CBC.SCCNCMP").options("shr"))                    cpp.dd(new DDStatement().dsn("CEE.SCEERUN").options("shr"))    cpp.dd(new DDStatement().name("SYSIN").dsn("${props.cpp_srcPDS}($member)").options('shr'))	    cpp.dd(new DDStatement().name("SYSLIB").dsn("CEE.SCEEH.H").options("shr"))                   cpp.dd(new DDStatement().dsn("CEE.SCEEH.SYS.H").options("shr"))                   cpp.dd(new DDStatement().dsn(props.cpp_headerPDS).options("shr"))	  def cppSyslibConcatenation = props.getFileProperty('cpp_assemblySyslibConcatenation', buildFile) ?: ""	  if (cppSyslibConcatenation) {		def StringÝ¨ syslibDatasets = cppSyslibConcatenation.split(',');		for (String syslibDataset : syslibDatasets )			cpp.dd(new DDStatement().dsn(syslibDataset).options("shr"))  	  }	cpp.dd(new DDStatement().name("SYSLIN").dsn("${props.cpp_objPDS}($member)").options('shr').output(true))	    cpp.dd(new DDStatement().name("SYSUT5").options(props.cpp_tempOptions))    cpp.dd(new DDStatement().name("SYSUT6").options(props.cpp_tempOptions))    cpp.dd(new DDStatement().name("SYSUT7").options(props.cpp_tempOptions))    cpp.dd(new DDStatement().name("SYSUT8").options(props.cpp_tempOptions))    cpp.dd(new DDStatement().name("SYSUT9").options(props.cpp_tempOptions))    cpp.dd(new DDStatement().name("SYSUT10").options(props.cpp_tempOptions))    cpp.dd(new DDStatement().name("SYSUT14").options(props.cpp_tempOptions))    cpp.dd(new DDStatement().name("SYSUT16").options(props.cpp_tempOptions))    cpp.dd(new DDStatement().name("SYSUT17").options(props.cpp_tempOptions))	cpp.dd(new DDStatement().name("SYSPRINT").options(props.cpp_tempOptions))	       cpp.dd(new DDStatement().name("SYSOUT").options(props.cpp_tempOptions))    cpp.dd(new DDStatement().name("SYSCPRT").options(props.cpp_tempOptions))    copyMod.copy(new CopyToHFS().ddName("SYSPRINT").file(logFile).hfsEncoding(props.logEncoding).append(true))			    copyMod.copy(new CopyToHFS().ddName("SYSOUT").file(logFile).hfsEncoding(props.logEncoding).append(true))			    copyMod.copy(new CopyToHFS().ddName("SYSCPRT").file(logFile).hfsEncoding(props.logEncoding).append(true))				return cpp}/* * createLinkEditCommand - creates a MVSExec xommand for link editing the cpp object module produced by the compile */def createLinkEditCommand(String buildFile, LogicalFile logicalFile, String member, File logFile) {	String parameters = props.getFileProperty('cpp_linkEditParms', buildFile)	// define the MVSExec command to link edit the program	MVSExec linkedit = new MVSExec().file(buildFile).pgm(props.cpp_linkEditor).parm(parameters)    linkedit.dd(new DDStatement().name("TASKLIB").dsn("CEE.SCEERUN2").options("shr"))                                        cpp.dd(new DDStatement().dsn("CEE.SCEERUN").options("shr"))                    cpp.dd(new DDStatement().dsn("CEE.SCEELKEX").options("shr"))                    cpp.dd(new DDStatement().dsn("CEE.SCEELKED").options("shr"))                    cpp.dd(new DDStatement().dsn("CEE.SCEECPP").options("shr"))		linkedit.dd(new DDStatement().name("SYSLIN").dsn("${cpp_objPDS}($member)").options('shr'))                   linkedit.dd(new DDStatement().dsn("CEE.SCEELIB(C128)").options('shr'))                   linkedit.dd(new DDStatement().dsn("CBC.SCLBSID(IOSTREAM)").options('shr'))                   linkedit.dd(new DDStatement().dsn("CBC.SCLBSID(COMPLEX)").options('shr'))		linkedit.dd(new DDStatement().name("SYSLIB").dsn("CEE.SCEELKEX").options("shr"))                   linkedit.dd(new DDStatement().dsn("CEE.SCEELKED").options("shr"))                   linkedit.dd(new DDStatement().dsn("CEE.SCEECPP").options("shr"))    	  	  def linkEditSyslibConcatenation = props.getFileProperty('cpp_linkEditSyslibConcatenation', buildFile) ?: ""	  if (linkEditSyslibConcatenation) {		def StringÝ¨ syslibDatasets = linkEditSyslibConcatenation.split(',');		for (String syslibDataset : syslibDatasets )			linkedit.dd(new DDStatement().dsn(syslibDataset).options("shr"))	  }	        String cpp_loadPDS = props.getFileProperty('cpp_loadPDS', buildFile)	String deployType = buildUtils.getDeployType("cpp", buildFile, logicalFile)	linkedit.dd(new DDStatement().name("SYSLMOD").dsn("${cpp_loadPDS}($member)").options('shr').output(true).deployType(deployType))	    linkedit.dd(new DDStatement().name("SYSPRINT").options(props.cpp_tempOptions))	linkedit.copy(new CopyToHFS().ddName("SYSPRINT").file(logFile).hfsEncoding(props.logEncoding).append(true))	return linkedit}def getRepositoryClient() {	if (!repositoryClient && props."dbb.RepositoryClient.url")		repositoryClient = new RepositoryClient().forceSSLTrusted(true)	return repositoryClient}